import { Component } from '@angular/core';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {

  timeoutTime = 3000;

  currentPhase = 0;

  failFlag = false;
  successFlag = false;
  
  phases = [
    {
      id: 0,
      title: '',
      content: '',
      nextPhase: 1,
      previousPhase: null,
      buttons: [
        {
          title: 'START!',
          callback: () => { this.goToNextPhase()}
        }
      ]
    },
    ////////////////////////////////////////////////////////////w
    {
      id: 1,
      title: 'Ya era hora señorita...',
      content: `
        Llevamos esperando demasiado tiempo su llegada, y tenemos malas noticias...
        Nos han informado que está esperando un listado de regalos, pero antes de ello tenemos
        que someterla a unas pruebas...
      `,
      nextPhase: 2,
      previousPhase: 0,
      buttons: [
        {
          title: 'Continuar',
          callback: () => { this.goToNextPhase() }
        }
      ]
    },
    ////////////////////////////////////////////////////////////
    {
      id: 2,
      title: '',
      content: `
        Lea con cautela las preguntas que recibirá a continuación, 
        y responda con cabeza.
      `,
      nextPhase: 3,
      previousPhase: 1,
      buttons: [
        {
          title: 'Volver',
          callback: () => { this.goToPreviousPhase() }
        },
        {
          title: 'Continuar',
          callback: () => { this.goToNextPhase() }
        }
      ]
    },
    ////////////////////////////////////////////////////////////
    {
      id: 3,
      title: 'Primera pregunta',
      content: `
        En múltiples ocasiones los desarrolladores de los videojuegos dejan unos "guiños"
        a los jugadores ¿con que nombre son conocidos estos guiños?
      `,
      nextPhase: 4,
      previousPhase: 2,
      buttons: [
        {
          title: 'Especial feature',
          callback: () => {
            this.showError();
          }
        },
        {
          title: 'Easter Egg',
          callback: () => { 
            this.goToNextPhase();
            this.showSuccess();
          }
        },
        {
          title: 'Deep ending',
          callback: () => {
            this.showError();
          }
        },
        {
          title: 'DevsIdea',
          callback: () => {
            this.showError();
          }
        },
      ]
    },
    ////////////////////////////////////////////////////////////
    {
      id: 4,
      title: 'Felicidades',
      content: `
        Reclame su primera recompensa!
      `,
      nextPhase: 5,
      previousPhase: 3,
      buttons: [
        {
          title: 'Continuar',
          callback: () => { 
            this.goToNextPhase()
          }
        },
      ]
    },
    ////////////////////////////////////////////////////////////
    {
      id: 5,
      title: 'Segunda pregunta',
      content: `
        ¿En que año fue creado el primer rompecabezas de la historia?
      `,
      nextPhase: 6,
      previousPhase: 4,
      buttons: [
        {
          title: '1888',
          callback: () => {
            this.showError();
          }
        },
        {
          title: '1900',
          callback: () => {
            this.showError();
          }
        },
        {
          title: '1565',
          callback: () => {
            this.showError();
          }
        },
        {
          title: '1762',
          callback: () => {
            this.goToNextPhase();
            this.showSuccess();
          }
        },
      ]
    },
    ////////////////////////////////////////////////////////////
    {
      id: 6,
      title: 'Felicidades',
      content: `
        Has completado tus pruebas ahora ve y disfruta de tu victoria!
      `,
      nextPhase: null,
      previousPhase: 5,
      buttons: []
    }
  ];

  constructor() {}

  checkCurrentPhase(id) {
    return this.currentPhase === id;
  }

  checkCurrentPhaseNot(id) {
    return this.currentPhase !== id;
  }

  goToNextPhase() {
    this.currentPhase = this.phases[this.currentPhase].nextPhase ?
      this.phases[this.currentPhase].nextPhase :
      this.currentPhase;
  }

  goToPreviousPhase() {
    this.currentPhase = this.phases[this.currentPhase].previousPhase ?
      this.phases[this.currentPhase].previousPhase :
      this.currentPhase;
  }

  showError() {
    this.failFlag = true;
    this.successFlag = false;
    setTimeout(() => {
      this.failFlag = false;
    }, this.timeoutTime);
  }

  showSuccess() {
    this.successFlag = true;
    this.failFlag = false;
    setTimeout(() => {
      this.successFlag = false;
    }, this.timeoutTime);
  }
}
